{
  "schema_version": 1,
  "request_id": "rf-suggest-edit-cross-object-mixed-risk-reconnect-compressor-mixed-parameter-patch-001",
  "project": "radishflow",
  "task": "suggest_flowsheet_edits",
  "status": "partial",
  "requires_confirmation": true,
  "answers": [
    {
      "summary": "当前围绕压缩机 compressor-22、分离器 separator-22 及其相连流股 separator-gas-94 的诊断生成候选提案，重点处理压缩机出口压力目标无效、最小流量旁路参数缺失、分离器固定压力缺参，以及分离器气相出口未连接的问题。",
      "issues": [
        {
          "title": "压缩机出口压力目标低于入口压力",
          "description": "compressor-22 当前采用 outlet_pressure 控制，但 outlet_pressure_target_kpa=165 低于入口流股 feed-94 的 190 kPa，直接触发无效目标诊断。",
          "citations": [
            "diag-2",
            "flowdoc-unit-1",
            "flowdoc-stream-1",
            "snapshot-1"
          ]
        },
        {
          "title": "压缩机最小流量旁路参数缺失",
          "description": "compressor-22 标记了 anti_surge_review_required=true，但缺少 minimum flow bypass percent 相关参数。",
          "citations": [
            "diag-3",
            "flowdoc-unit-1",
            "snapshot-1"
          ]
        },
        {
          "title": "分离器固定压力模式缺少目标压力",
          "description": "separator-22 设置为 fixed pressure mode，但未提供 operating pressure target。",
          "citations": [
            "diag-4",
            "flowdoc-unit-2",
            "snapshot-1"
          ]
        },
        {
          "title": "分离器气相出口未连接",
          "description": "separator-gas-94 当前没有下游消费者或导出端；同时该路由仍受当前压缩机排出与分离器压力上下文影响，证据不足以指定唯一目的端。",
          "citations": [
            "diag-1",
            "diag-6",
            "flowdoc-stream-3",
            "snapshot-1"
          ]
        }
      ],
      "proposed_actions": [
        {
          "action": "candidate_edit",
          "title": "为压缩机出口压力目标改为待确认占位值",
          "target": {
            "type": "unit",
            "id": "compressor-22"
          },
          "rationale": "现有 outlet_pressure_target_kpa 明确低于入口压力，需先将无效设定替换为高于入口压力的待确认目标，避免继续保留已知矛盾值；但具体目标压力缺少工艺依据，宜仅提交占位修补。",
          "patch": {
            "parameter_placeholders": [
              {
                "path": "config.outlet_pressure_target_kpa",
                "expected_relation": {
                  "gt_path": "connected_inlet_stream.specs.pressure_kpa"
                },
                "current_value": 165,
                "context_note": "feed-94 pressure_kpa is 190; confirm compressor discharge target above inlet and consistent with downstream separator pressure."
              }
            ]
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-2",
            "flowdoc-unit-1",
            "flowdoc-stream-1",
            "snapshot-1"
          ]
        },
        {
          "action": "candidate_edit",
          "title": "为压缩机补充最小流量旁路百分比占位参数",
          "target": {
            "type": "unit",
            "id": "compressor-22"
          },
          "rationale": "诊断直接指出 anti-surge review 需要 minimum flow bypass percent，但当前缺失；在缺乏数值依据时，仅补充待确认参数占位最小且可审查。",
          "patch": {
            "parameter_placeholders": [
              {
                "path": "config.minimum_flow_bypass_percent",
                "expected_range": {
                  "min": 0,
                  "max": 100
                },
                "context_note": "Required because anti_surge_review_required=true; confirm compressor anti-surge minimum flow bypass setting."
              }
            ]
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-3",
            "flowdoc-unit-1",
            "snapshot-1"
          ]
        },
        {
          "action": "candidate_edit",
          "title": "为固定压力分离器补充操作压力目标占位",
          "target": {
            "type": "unit",
            "id": "separator-22"
          },
          "rationale": "separator-22 已配置为 fixed pressure mode，但缺少 operating pressure target；直接补充占位字段可对应当前诊断而不引入未证实数值。",
          "patch": {
            "parameter_placeholders": [
              {
                "path": "config.operating_pressure_target_kpa",
                "context_note": "Required for pressure_mode=fixed; confirm target consistent with compressor discharge and separator outlet conditions."
              }
            ]
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-4",
            "flowdoc-unit-2",
            "snapshot-1"
          ]
        },
        {
          "action": "candidate_edit",
          "title": "为未连接气相出口添加下游连接占位",
          "target": {
            "type": "stream",
            "id": "separator-gas-94"
          },
          "rationale": "separator-gas-94 明确未连接，但诊断同时说明其路由依赖当前压缩机排出与分离器压力上下文，因此只能提出连接占位而不能指定具体下游对象或执行重连。",
          "patch": {
            "connection_placeholder": {
              "stream_id": "separator-gas-94",
              "missing_endpoint": "downstream_consumer_or_export_sink",
              "context_note": "Select a downstream consumer or export sink after confirming compressor discharge target and separator operating pressure."
            }
          },
          "risk_level": "high",
          "requires_confirmation": true,
          "citations": [
            "diag-1",
            "diag-6",
            "flowdoc-stream-3",
            "snapshot-1"
          ]
        }
      ],
      "confidence": 0.87
    }
  ],
  "citations": [
    {
      "id": "diag-1",
      "type": "diagnostic",
      "code": "STREAM_DISCONNECTED"
    },
    {
      "id": "diag-2",
      "type": "diagnostic",
      "code": "COMPRESSOR_OUTLET_PRESSURE_TARGET_INVALID"
    },
    {
      "id": "diag-3",
      "type": "diagnostic",
      "code": "COMPRESSOR_MINIMUM_FLOW_BYPASS_MISSING"
    },
    {
      "id": "diag-4",
      "type": "diagnostic",
      "code": "UNIT_PARAMETER_INCOMPLETE"
    },
    {
      "id": "diag-5",
      "type": "diagnostic",
      "code": "UNIT_PARAMETER_OUT_OF_RANGE"
    },
    {
      "id": "diag-6",
      "type": "diagnostic",
      "code": "DOWNSTREAM_STATE_DEPENDENT"
    },
    {
      "id": "flowdoc-stream-1",
      "type": "artifact",
      "artifact_name": "flowsheet_document",
      "path": "$.content.streams[0]"
    },
    {
      "id": "flowdoc-stream-2",
      "type": "artifact",
      "artifact_name": "flowsheet_document",
      "path": "$.content.streams[1]"
    },
    {
      "id": "flowdoc-stream-3",
