      "path": "$.content.streams[2]"
    },
    {
      "id": "flowdoc-unit-1",
      "type": "artifact",
      "artifact_name": "flowsheet_document",
      "path": "$.content.units[0]"
    },
    {
      "id": "flowdoc-unit-2",
      "type": "artifact",
      "artifact_name": "flowsheet_document",
      "path": "$.content.units[1]"
    },
    {
      "id": "snapshot-1",
      "type": "snapshot",
      "solver_status": "invalid_topology",
      "timestamp": "2026-04-16T02:25:00Z"
    }
  ]
}
